-- Auth ユーザー作成後に実行
-- watanabe@hitoshi.cloud 用。users 行（seed.sql 19-25行）は含めません。
-- companies も含むため、このファイルだけ Run すれば OK

-- ② 会社マスタ（未投入なら先にこれが必要）
on conflict (id) do nothing;

-- ③ プロフィール紐づけ
on conflict (id) do update set
  company_id = excluded.company_id,
  name = excluded.name,
  email = excluded.email,
  role = excluded.role,
  is_active = excluded.is_active;

